// ─── Helpers ───────────────────────────────────────────────
function formatPct(v) {
  if (typeof v === 'number') return (v * 100).toFixed(1) + '%';
  if (typeof v === 'string') return v;
  return '--';
}

function metricsToArray(obj) {
  if (!obj || typeof obj !== 'object') return FALLBACK_METRICS;
  const map = {
    accuracy: 'Accuracy',
    precision: 'Precision',
    recall: 'Recall',
    f1_score: 'F1 Score',
    auc_roc: 'AUC-ROC',
    sharpe: 'Sharpe',
  };
  return Object.entries(obj).map(([k, v]) => ({
    label: map[k] || k,
    value: k === 'sharpe' ? (v != null ? v.toFixed(2) : '--') : formatPct(v),
    raw: v,
  }));
}

function timeAgo(dateStr) {
  if (!dateStr) return '--';
  const d = new Date(dateStr);
  const now = new Date();
  const diffMs = now - d;
  if (diffMs < 0) return 'scheduled';
  const mins = Math.floor(diffMs / 60000);
  if (mins < 60) return `${mins}m ago`;
  const hours = Math.floor(mins / 60);
  if (hours < 24) return `${hours}h ago`;
  const days = Math.floor(hours / 24);
  return `${days}d ago`;
}

function healthColor(status) {
  if (!status) return colors.textSecondary;
  const s = String(status).toLowerCase();
  if (s === 'healthy' || s === 'active' || s === 'ok' || s === 'online' || s === 'good') return colors.green;
  if (s === 'degraded' || s === 'warning' || s === 'stale') return colors.amber;
  return colors.red;
}

function driftSeverityColor(score) {
  if (score == null) return colors.textSecondary;
  if (score < 0.1) return colors.green;
  if (score < 0.2) return colors.amber;
  return colors.red;
}

function driftSeverityLabel(score) {
  if (score == null) return 'Unknown';
  if (score < 0.1) return 'Low';
  if (score < 0.2) return 'Medium';
  return 'High';
}

// ─── Feature Importance Chart ──────────────────────────────
function FeatureImportanceChart({ features, loading }) {
  if (loading) {
    return <div className={s.loadingText}>Loading feature data...</div>;
  }
  if (!features || features.length === 0) {
    return <div className={s.loadingText}>No feature importance data available</div>;
  }

  const maxVal = Math.max(...features.map((f) => f.value));
  const barMaxWidth = 320;
  const barHeight = 24;
  const rowGap = 10;

  return (
    <svg
      width="100%"
      viewBox={`0 0 460 ${features.length * (barHeight + rowGap)}`}
      className={s.featureChart}
    >
      {features.map((f, i) => {
        const y = i * (barHeight + rowGap);
        const w = maxVal > 0 ? (f.value / maxVal) * barMaxWidth : 0;
        return (
          <g key={f.name}>
            <text
              x={110}
              y={y + barHeight / 2 + 4}
              textAnchor="end"
              fill={colors.textSecondary}
              fontSize="12"
              fontFamily={mono}
            >
              {f.name}
            </text>
            <rect
              x={120}
              y={y}
              width={barMaxWidth}
              height={barHeight}
              rx={4}
              fill={colors.surface2}
            />
            <rect
              x={120}
              y={y}
              width={w}
              height={barHeight}
              rx={4}
              fill={colors.purple}
              opacity={0.8}
            />
            <text
              x={120 + w + 8}
              y={y + barHeight / 2 + 4}
              fill={colors.textPrimary}
              fontSize="12"
              fontFamily={mono}
              fontWeight="600"
            >
              {(f.value ?? 0).toFixed(2)}
            </text>
          </g>
        );
      })}
    </svg>
  );
}

