// ─── Strategy Performance Heatmap (last 12 months) ─────────
function StrategyHeatmap({ data, loading }) {
  const months = getLast12Months();

  if (loading) return <div className={s.loadingText}>Loading heatmap data...</div>;

  // data: array of { strategy, monthly: { "2026-01": 3.2, "2026-02": -1.1, ... } }
  if (!data || data.length === 0) {
    return (
      <div className={s.heatmapEmpty}>
        No strategy performance data available. Run backtests to populate.
      </div>
    );
  }

  const cellColor = (val) => {
    if (val == null) return 'rgba(139,148,158,0.08)';
    if (val >= 5)   return 'rgba(63,185,80,0.75)';
    if (val >= 2)   return 'rgba(63,185,80,0.45)';
    if (val >= 0)   return 'rgba(63,185,80,0.2)';
    if (val >= -2)  return 'rgba(248,81,73,0.2)';
    if (val >= -5)  return 'rgba(248,81,73,0.45)';
    return 'rgba(248,81,73,0.75)';
  };

  const textColor = (val) => {
    if (val == null) return colors.textSecondary;
    return val >= 0 ? colors.green : colors.red;
  };

  return (
    <div className={s.heatmapScroll}>
      <table className={s.heatmapTable}>
        <thead>
          <tr>
            <th className={s.heatmapStrategyHeader}>Strategy</th>
            {months.map(m => (
              <th key={`${m.year}-${m.month}`} className={s.heatmapMonthHeader}>{m.label}</th>
            ))}
            <th className={s.heatmapMonthHeader}>Avg</th>
          </tr>
        </thead>
        <tbody>
          {data.map((row, i) => {
            const vals = months.map(m => {
              const key = `${m.year}-${String(m.month).padStart(2, '0')}`;
              const v = row.monthly?.[key];
              return v != null ? Number(v) : null;
            });
            const nonNull = vals.filter(v => v != null);
            const avg = nonNull.length > 0 ? nonNull.reduce((a, b) => a + b, 0) / nonNull.length : null;
            return (
              <tr key={i} className={s.heatmapRow}>
                <td className={s.heatmapStrategyCell} title={row.strategy}>{row.strategy}</td>
                {vals.map((val, j) => (
                  <td key={j} className={s.heatmapCell} style={{ background: cellColor(val) }}>
                    <span style={{ color: textColor(val), fontFamily: mono, fontSize: 10 }}>
                      {val != null ? (val >= 0 ? '+' : '') + val.toFixed(1) + '%' : '—'}
                    </span>
                  </td>
                ))}
                <td className={s.heatmapCell} style={{ background: cellColor(avg), borderLeft: `1px solid ${colors.border}` }}>
                  <span style={{ color: textColor(avg), fontFamily: mono, fontSize: 10, fontWeight: 700 }}>
                    {avg != null ? (avg >= 0 ? '+' : '') + avg.toFixed(1) + '%' : '—'}
                  </span>
                </td>
              </tr>
            );
          })}
        </tbody>
      </table>
    </div>
  );
}

