// ─── Ensemble Signal Strength ───────────────────────────────
function EnsembleSignalCard({ signals, loading }) {
  if (loading) return <div className={s.loadingText}>Loading ensemble signals...</div>;
  if (!signals || signals.length === 0) {
    return <div className={s.loadingText}>No ensemble signals available</div>;
  }

  return (
    <div className={s.ensembleList}>
      {signals.map((sig, i) => {
        const strength = sig.strength ?? sig.confidence ?? sig.score ?? 0;
        const pct = Math.min(Math.max(Number(strength) * 100, 0), 100);
        const barColor = pct >= 70 ? colors.green : pct >= 45 ? colors.amber : colors.red;
        const direction = sig.direction || sig.signal || '';
        const dirColor = direction === 'long' || direction === 'buy' || direction === 'bullish'
          ? colors.green
          : direction === 'short' || direction === 'sell' || direction === 'bearish'
          ? colors.red
          : colors.textSecondary;

        return (
          <div key={i} className={s.ensembleRow}>
            <div className={s.ensembleRowTop}>
              <span className={s.ensembleSymbol}>{sig.symbol || sig.strategy || sig.name}</span>
              {direction && (
                <span style={{ color: dirColor, fontSize: 10, fontFamily: mono, textTransform: 'uppercase', fontWeight: 700 }}>
                  {direction}
                </span>
              )}
              <span style={{ color: barColor, fontFamily: mono, fontSize: 12, fontWeight: 700, marginLeft: 'auto' }}>
                {pct.toFixed(0)}%
              </span>
            </div>
            <div className={s.ensembleBarTrack}>
              <div className={s.ensembleBarFill} style={{ width: `${pct}%`, background: barColor }} />
            </div>
            {sig.models_agreeing != null && (
              <div style={{ fontSize: 10, color: colors.textSecondary, marginTop: 2 }}>
                {sig.models_agreeing} models agreeing
              </div>
            )}
          </div>
        );
      })}
    </div>
  );
}

