// ─── Model Drift Section ──────────────────────────────────
function DriftDetectionSection({ driftData, loading }) {
  if (loading) return <div className={s.loadingText}>Loading drift data...</div>;
  if (!driftData) return <div className={s.loadingText}>No drift data available</div>;

  const strategies = driftData.strategies || [];
  const metrics = driftData.metrics || {};
  const featureDrift = driftData.feature_drift || [];
  const recommendations = driftData.recommendations || [];

  const avgPsi = metrics.avg_psi ?? metrics.psi ?? metrics.max_drift_score ?? null;
  const avgKs = metrics.avg_ks ?? metrics.ks ?? metrics.win_rate_drift ?? null;
  const daysSinceRetrain = metrics.days_since_retrain ?? null;
  const driftingCount = strategies.filter(st => {
    const stStatus = (st.status || '').toUpperCase();
    return stStatus.includes('DRIFT') || (st.drift_score != null && st.drift_score >= 0.2);
  }).length;

  return (
    <div className={s.driftSection}>
      {/* Drift summary stats */}
      <div className={s.driftStatsRow}>
        <div className={s.driftStatBox}>
          <div className={s.driftStatLabel}>Avg PSI</div>
          <div className={s.driftStatValue} style={{ color: driftSeverityColor(avgPsi) }}>
            {avgPsi != null ? avgPsi.toFixed(3) : '--'}
          </div>
        </div>
        <div className={s.driftStatBox}>
          <div className={s.driftStatLabel}>Avg KS</div>
          <div className={s.driftStatValue} style={{ color: driftSeverityColor(avgKs) }}>
            {avgKs != null ? avgKs.toFixed(3) : '--'}
          </div>
        </div>
        <div className={s.driftStatBox}>
          <div className={s.driftStatLabel}>Drifting Models</div>
          <div className={s.driftStatValue} style={{ color: driftingCount > 0 ? colors.red : colors.green }}>
            {driftingCount} / {strategies.length || '--'}
          </div>
        </div>
        <div className={s.driftStatBox}>
          <div className={s.driftStatLabel}>Days Since Retrain</div>
          <div className={s.driftStatValue} style={{ color: daysSinceRetrain != null && daysSinceRetrain > 14 ? colors.red : daysSinceRetrain != null && daysSinceRetrain > 7 ? colors.amber : colors.green }}>
            {daysSinceRetrain ?? '--'}
          </div>
        </div>
      </div>

      {/* Feature drift bars */}
      {featureDrift.length > 0 && (
        <div className={s.driftFeatureSection}>
          <div className={s.driftFeatureTitle}>Feature Drift (PSI)</div>
          {featureDrift.slice(0, 10).map((fd, i) => {
            const psi = fd.psi ?? fd.drift_score ?? fd.value ?? 0;
            const maxPsi = 0.5; // scale bar to 0.5 max
            const pct = Math.min((psi / maxPsi) * 100, 100);
            return (
              <div key={fd.feature || fd.name || i} className={s.driftFeatureRow}>
                <span className={s.driftFeatureName}>{fd.feature || fd.name || `Feature ${i + 1}`}</span>
                <div className={s.driftFeatureBarTrack}>
                  <div
                    className={s.driftFeatureBarFill}
                    style={{ width: `${pct}%`, background: driftSeverityColor(psi) }}
                  />
                </div>
                <span className={s.driftFeatureValue} style={{ color: driftSeverityColor(psi) }}>
                  {psi.toFixed(3)}
                </span>
              </div>
            );
          })}
        </div>
      )}

      {/* Strategy drift table */}
      {strategies.length > 0 && (
        <div className={s.driftTableSection}>
          <div className={s.driftFeatureTitle}>Strategy Drift Scores</div>
          <table className={s.winRateTable}>
            <thead>
              <tr className={s.winRateHeaderRow}>
                <th className={s.winRateHeader}>Strategy</th>
                <th className={s.winRateHeader}>Drift Score</th>
                <th className={s.winRateHeader}>Severity</th>
                <th className={s.winRateHeader}>Status</th>
              </tr>
            </thead>
            <tbody>
              {strategies.slice(0, 15).map((st, i) => {
                const score = st.drift_score ?? 0;
                return (
                  <tr key={i} className={s.winRateRow}>
                    <td className={s.winRateCell}>{st.strategy || st.name || st.id}</td>
                    <td className={s.winRateCellMono} style={{ color: driftSeverityColor(score) }}>
                      {score.toFixed(3)}
                    </td>
                    <td className={s.winRateCellMono} style={{ color: driftSeverityColor(score) }}>
                      {driftSeverityLabel(score)}
                    </td>
                    <td className={s.winRateCellMono} style={{ color: healthColor(st.status || (score >= 0.2 ? 'degraded' : 'healthy')) }}>
                      {(st.status || (score >= 0.2 ? 'DRIFTING' : 'STABLE')).toUpperCase()}
                    </td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        </div>
      )}

      {/* Recommendations */}
      {recommendations.length > 0 && (
        <div className={s.driftRecommendations}>
          <div className={s.driftFeatureTitle}>Recommendations</div>
          {recommendations.map((rec, i) => (
            <div key={i} className={s.driftRecItem}>
              <span className={s.driftRecBullet} style={{ color: rec.urgency === 'HIGH' ? colors.red : rec.urgency === 'MEDIUM' ? colors.amber : colors.green }}>
                {rec.urgency === 'HIGH' ? '!' : rec.urgency === 'MEDIUM' ? '*' : '-'}
              </span>
              <span>{typeof rec === 'string' ? rec : rec.message || rec.recommendation || rec.text || JSON.stringify(rec)}</span>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}

// ─── Retraining History Section ────────────────────────────
